import { useRef, useState } from 'react';
import { useOutletContext } from 'react-router-dom';

import type {
  DocumentFile,
    Project,
    } from '../../models/types';

    import { saveProject } from '../../database/database';

    import AppCard from '../../components/cards/AppCard';
    import DateInput from '../../components/forms/DateInput';
    import SelectInput from '../../components/forms/SelectInput';
    import SuggestInput from '../../components/forms/SuggestInput';
    import TextAreaInput from '../../components/forms/TextAreaInput';

    import {
      DOCUMENT_TYPES,
      } from '../../utils/constants';

      import {
        now,
          today,
            uid,
            } from '../../utils/format';

            type Ctx = {
              project: Project;
              };

              export default function Documents() {
                const { project } =
                    useOutletContext<Ctx>();

                      const [p, setP] =
                          useState<Project>(project);

                            const [docs, setDocs] =
                                useState<DocumentFile[]>(
                                      project.documents
                                          );

                                            const fileRef =
                                                useRef<HTMLInputElement>(null);

                                                  const [title, setTitle] =
                                                      useState('');

                                                        const [type, setType] =
                                                            useState(DOCUMENT_TYPES[0]);

                                                              const [date, setDate] =
                                                                  useState(today());

                                                                    const [notes, setNotes] =
                                                                        useState('');

                                                                          const save = () => {
                                                                              const file =
                                                                                    fileRef.current?.files?.[0];

                                                                                        if (!file || !title) return;

                                                                                            const reader =
                                                                                                  new FileReader();

                                                                                                      reader.onload = () => {
                                                                                                            const row: DocumentFile = {
                                                                                                                    id: uid(),
                                                                                                                            projectId: p.id,
                                                                                                                                    title,
                                                                                                                                            type,
                                                                                                                                                    fileName: file.name,
                                                                                                                                                            fileType: file.type,
                                                                                                                                                                    dataUrl:
                                                                                                                                                                              reader.result as string,
                                                                                                                                                                                      date,
                                                                                                                                                                                              notes,
                                                                                                                                                                                                      createdAt: now(),
                                                                                                                                                                                                            };

                                                                                                                                                                                                                  const updatedDocs = [
                                                                                                                                                                                                                          row,
                                                                                                                                                                                                                                  ...docs,
                                                                                                                                                                                                                                        ];

                                                                                                                                                                                                                                              const updatedProject: Project = {
                                                                                                                                                                                                                                                      ...p,
                                                                                                                                                                                                                                                              documents: updatedDocs,
                                                                                                                                                                                                                                                                      updatedAt: now(),
                                                                                                                                                                                                                                                                            };

                                                                                                                                                                                                                                                                                  saveProject(updatedProject);

                                                                                                                                                                                                                                                                                        setP(updatedProject);
                                                                                                                                                                                                                                                                                              setDocs(updatedDocs);

                                                                                                                                                                                                                                                                                                    setTitle('');
                                                                                                                                                                                                                                                                                                          setNotes('');
                                                                                                                                                                                                                                                                                                                setDate(today());
                                                                                                                                                                                                                                                                                                                      setType(DOCUMENT_TYPES[0]);

                                                                                                                                                                                                                                                                                                                            if (fileRef.current) {
                                                                                                                                                                                                                                                                                                                                    fileRef.current.value = '';
                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                              };

                                                                                                                                                                                                                                                                                                                                                  reader.readAsDataURL(file);
                                                                                                                                                                                                                                                                                                                                                    };

                                                                                                                                                                                                                                                                                                                                                      const remove = (id: string) => {
                                                                                                                                                                                                                                                                                                                                                          if (!confirm('حذف المستند؟')) return;

                                                                                                                                                                                                                                                                                                                                                              const updatedDocs =
                                                                                                                                                                                                                                                                                                                                                                    docs.filter(doc => doc.id !== id);

                                                                                                                                                                                                                                                                                                                                                                        const updatedProject: Project = {
                                                                                                                                                                                                                                                                                                                                                                              ...p,
                                                                                                                                                                                                                                                                                                                                                                                    documents: updatedDocs,
                                                                                                                                                                                                                                                                                                                                                                                          updatedAt: now(),
                                                                                                                                                                                                                                                                                                                                                                                              };

                                                                                                                                                                                                                                                                                                                                                                                                  saveProject(updatedProject);

                                                                                                                                                                                                                                                                                                                                                                                                      setP(updatedProject);
                                                                                                                                                                                                                                                                                                                                                                                                          setDocs(updatedDocs);
                                                                                                                                                                                                                                                                                                                                                                                                            };

                                                                                                                                                                                                                                                                                                                                                                                                              return (
                                                                                                                                                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="section-title-box">
                                                                                                                                                                                                                                                                                                                                                                                                                                <h2>📁 المستندات</h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                            <AppCard title="📂 إضافة مستند">
                                                                                                                                                                                                                                                                                                                                                                                                                                                    <SuggestInput
                                                                                                                                                                                                                                                                                                                                                                                                                                                              label="عنوان المستند"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        value={title}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  typeKey="documentTitles"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onChange={setTitle}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <SelectInput
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      label="النوع"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                value={type}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          options={DOCUMENT_TYPES.map(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      x => ({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    value: x,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  label: x,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  onChange={setType}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <DateInput
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            label="التاريخ"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      value={date}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onChange={setDate}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <label className="field">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span>الملف</span>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ref={fileRef}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            type="file"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </label>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <TextAreaInput
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                label="ملاحظات"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          value={notes}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onChange={setNotes}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              className="btn primary"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        onClick={save}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          حفظ المستند
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </AppCard>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <AppCard title="قائمة المستندات">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {!docs.length && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="empty-state">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            لا توجد مستندات حالياً
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="grid">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {docs.map((doc) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className="card"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        key={doc.id}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <h3>{doc.title}</h3>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <b>النوع:</b>{' '}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {doc.type}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <b>التاريخ:</b>{' '}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {doc.date}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <b>الملف:</b>{' '}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {doc.fileName}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {doc.notes && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p>{doc.notes}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="row">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <a
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className="btn primary"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    href={doc.dataUrl}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      target="_blank"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        rel="noreferrer"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          فتح المستند
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </a>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            className="btn danger"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onClick={() => remove(doc.id)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                حذف
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </AppCard>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }